const e=JSON.parse('{"key":"v-2ccf26e9","path":"/posts/JavaScript%E7%9A%84%E5%8E%9F%E5%9E%8B%E4%B8%8E%E7%BB%A7%E6%89%BF.html","title":"JavaScript的原型与继承","lang":"zh-CN","frontmatter":{"title":"JavaScript的原型与继承","isTimeLine":true,"date":"2025-03-28T00:00:00.000Z","category":["前端"],"tag":["JavaScript"]},"headers":[{"level":3,"title":"原型与原型链？","slug":"原型与原型链","link":"#原型与原型链","children":[]},{"level":3,"title":"对象继承几种方式？","slug":"对象继承几种方式","link":"#对象继承几种方式","children":[]},{"level":3,"title":"类与继承","slug":"类与继承","link":"#类与继承","children":[]},{"level":3,"title":"扩展运算符 解构 rest参数","slug":"扩展运算符-解构-rest参数","link":"#扩展运算符-解构-rest参数","children":[]},{"level":3,"title":"proxy可以实现什么功能？","slug":"proxy可以实现什么功能","link":"#proxy可以实现什么功能","children":[]},{"level":3,"title":"ES6模块与CommonJS模块有什么异同？","slug":"es6模块与commonjs模块有什么异同","link":"#es6模块与commonjs模块有什么异同","children":[]},{"level":3,"title":"链接","slug":"链接","link":"#链接","children":[]}],"git":{"createdTime":1773286516000,"updatedTime":1773286516000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":6.71,"words":2013},"filePathRelative":"posts/JavaScript的原型与继承.md","localizedDate":"2025年3月28日","excerpt":"<h3> 原型与原型链？</h3>\\n<ol>\\n<li>函数的prototype属性: 在定义函数时自动添加的, 默认值是一个空Object对象</li>\\n<li>对象的__proto__属性: 创建对象时自动添加的, 默认值为构造函数的prototype属性值</li>\\n<li>构造函数、实例、原型对象三者之间的关系</li>\\n</ol>\\n<blockquote>\\n<ul>\\n<li>每个构造函数会创建一个<code>prototype</code>属性指向原型对象，这个对象包含了该构造函数的所有实例共享的属性和方法；</li>\\n<li>原型对象会有一个<code>constructor</code>属性指回构造函数；</li>\\n<li>当我们使用构造函数去创建实例时，实例的<code>__proto__</code>属性就会指向构造函数的原型对象。</li>\\n</ul>\\n</blockquote>"}');export{e as data};
